import React, { useState } from 'react';
import axios from "axios";
import { useNavigate } from 'react-router-dom';  // Import useNavigate
import styles from '../styles/styles.css';

axios.defaults.withCredentials = true; // Ensure cookies are included in requests

// import {config} from "dotenv";

const LoginPage = () => {
    // const [email, setEmail] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [isLoading, setIsLoading] = useState(false);

    const navigate = useNavigate();  // Initialize the navigate hook

    const handleSubmit = async (e) => {
        console.log("handleSubmit", e);
        e.preventDefault();

        console.log("Login with:\nemail: " + email + "\nPassword: " + password);

        if (!email || !password) {
            setError('Please enter both userName and password');
            return;
        }

        setIsLoading(true);
        setError('');

        try {
            let response= await axios.post("http://localhost:3003/user/login", {
                email: email,
                password: password
            })

            console.log("response is: " + response);

            if (200 !== response.status) {
                throw new Error('Login failed, please try again.');
            }

            // Handle successful login here (e.g., redirect to dashboard)
            console.log('Login successful');

            let token = response.data.token;
            console.log("response.data.token: " + token);
            sessionStorage.setItem('token', response.data.token);


            // axios.AxiosHeaders.common['Authorization'] = 'Bearer ' + token;

            console.log("navigeting to profile...");
            navigate('/profile');
        } catch (err) {
            setError(err.message || 'An error occurred');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div style={styles.container}>
            <h2>Login to Your Account</h2>
            {error && <div style={styles.error}>{error}</div>}
            <form onSubmit={handleSubmit}>
                <div style={styles.inputContainer}>
                    <label>Email</label>
                    <input
                        type="string"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        style={styles.input}
                        placeholder="Enter your user name"
                    />
                </div>
                <div style={styles.inputContainer}>
                    <label>Password</label>
                    <input
                        type="password"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        style={styles.input}
                        placeholder="Enter your password"
                    />
                </div>
                <button type="submit" style={styles.button} disabled={isLoading}>
                    {isLoading ? 'Logging in...' : 'Login'}
                </button>
            </form>
            <div style={styles.redirect}>
                <p>Don't have an account? <a href="/register">Register here</a></p>
            </div>
        </div>
    );
};

